## 4. Integração no middleware (js/chat-models.js)

### 4.1. Modificação de callModelWithRetry

A função `callModelWithRetry` foi modificada para tentar a API local primeiro:

**Antes:**
```javascript
async function callModelWithRetry(payload, retries = 2) {
  const requestedModel = payload?.model || null;
  const resolvedModel = resolveModelId(requestedModel);
  const provider = getModelProvider(resolvedModel);

  console.log('[MODEL ROUTE]', {
    requestedModel,
    resolvedModel,
    provider
  });

  if (provider === 'deepseek') {
    return callDeepSeekWithRetry({ ...payload, model: resolvedModel }, retries);
  }

  if (provider === 'openai') {
    return callOpenAIProviderWithRetry({ ...payload, model: resolvedModel }, retries);
  }

  if (provider === 'anthropic') {
    return callAnthropicWithRetry({ ...payload, model: resolvedModel }, retries);
  }

  throw new Error(`[MODEL ROUTE] Provider desconhecido para modelo: ${resolvedModel}`);
}
```

**Depois:**
```javascript
async function callModelWithRetry(payload, retries = 2) {
  const requestedModel = payload?.model || null;
  const resolvedModel = resolveModelId(requestedModel);
  const provider = getModelProvider(resolvedModel);

  console.log('[MODEL ROUTE]', {
    requestedModel,
    resolvedModel,
    provider
  });

  // Tentar API local primeiro
  if (typeof worionApiChatMessages === 'function') {
    try {
      console.log('[MODEL CALL] Tentando Worion API local');
      const result = await worionApiChatMessages(
        payload.messages || [],
        resolvedModel,
        {
          temperature: payload.temperature,
          max_tokens: payload.max_tokens || payload.max_completion_tokens || payload.maxTokens,
          tools: payload.tools,
          tool_choice: payload.tool_choice
        }
      );

      console.log('[MODEL CALL] Worion API respondeu:', {
        model: result.model,
        provider: result.provider,
        contentLength: result.content?.length || 0
      });

      // Adaptar resposta da API local para formato esperado
      return {
        choices: [{
          message: {
            content: result.content,
            tool_calls: result.tool_calls || []
          },
          finish_reason: result.finish_reason || 'stop'
        }],
        usage: result.usage || {},
        model: result.model
      };
    } catch (error) {
      console.warn('[MODEL CALL] Worion API falhou, usando fallback direto:', error.message);
    }
  }

  // Fallback: chamada direta ao provedor
  console.log('[MODEL CALL] Usando fallback direto ao provedor');
  if (provider === 'deepseek') {
    return callDeepSeekWithRetry({ ...payload, model: resolvedModel }, retries);
  }

  if (provider === 'openai') {
    return callOpenAIProviderWithRetry({ ...payload, model: resolvedModel }, retries);
  }

  if (provider === 'anthropic') {
    return callAnthropicWithRetry({ ...payload, model: resolvedModel }, retries);
  }

  throw new Error(`[MODEL ROUTE] Provider desconhecido para modelo: ${resolvedModel}`);
}
```

**Fluxo:**
1. ✅ Verifica se `worionApiChatMessages` existe no window
2. ✅ Tenta chamar API local
3. ✅ Adapta resposta da API local para formato esperado pelo chat.js
4. ✅ Se API local falhar (timeout, erro, indisponível), usa fallback direto
5. ✅ Log em cada etapa para debug

**Adaptação de resposta:**
- API local retorna: `{ content, model, provider, usage, finish_reason, tool_calls }`
- Formato esperado: `{ choices: [{ message: { content, tool_calls }, finish_reason }], usage, model }`
- A adaptação é feita no middleware antes de retornar ao chat.js

