### 5.3. Teste local da rota

Foi criado `test-chat-api.js` (adicionado ao `.gitignore` como padrão `test-*.js`):

```javascript
const http = require('http');

function makeRequest(path, body) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const options = {
      hostname: '127.0.0.1',
      port: 3766,
      path,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(data)
      }
    };

    const req = http.request(options, (res) => {
      let responseData = '';
      res.on('data', chunk => responseData += chunk);
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, data: JSON.parse(responseData) });
        } catch {
          resolve({ status: res.statusCode, data: responseData });
        }
      });
    });

    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

async function testChatAPI() {
  console.log('Iniciando teste local da API de chat...\n');

  // Teste 1: Validação de payload (sem messages)
  console.log('=== Teste 1: Validação de payload ===');
  try {
    const { status, data } = await makeRequest('/api/chat/messages', {});
    console.log('Status:', status);
    console.log('Resposta:', JSON.stringify(data, null, 2));
    if (status === 400 && !data.ok) {
      console.log('✓ Validação de payload funcionou\n');
    } else {
      console.log('⚠ Resposta inesperada\n');
    }
  } catch (error) {
    console.error('✗ Teste 1 falhou:', error.message, '\n');
  }

  // Teste 2: Payload válido mínimo (vai falhar sem .env, mas testa o fluxo)
  console.log('=== Teste 2: Payload válido mínimo ===');
  try {
    const { status, data } = await makeRequest('/api/chat/messages', {
      messages: [
        { role: 'user', content: 'Olá, isso é um teste' }
      ],
      model: 'gpt-4o-mini',
      tenant_id: 'test',
      user_id: 'test-user'
    });
    console.log('Status:', status);
    console.log('Resposta resumida:', {
      ok: data.ok,
      hasContent: !!data.content,
      contentLength: data.content?.length || 0,
      model: data.model,
      provider: data.provider,
      error: data.error ? data.error.slice(0, 100) : undefined
    });

    if (data.ok && data.content) {
      console.log('✓ Chat API processou mensagem com sucesso\n');
    } else if (data.error && (
      data.error.includes('key') ||
      data.error.includes('Vault') ||
      data.error.includes('WORION_')
    )) {
      console.log('⚠ API key não configurada (esperado em ambiente de teste)\n');
    } else {
      console.log('⚠ Resposta inesperada:', data.error, '\n');
    }
  } catch (error) {
    console.error('✗ Teste 2 falhou:', error.message, '\n');
  }

  console.log('=== Testes concluídos ===');
}

testChatAPI().catch(error => {
  console.error('Erro nos testes:', error);
  process.exit(1);
});
```

