## 2. Implementação no backend (worion-api/server.js)

### 2.1. Funções para resolver API keys

Adicionadas funções para buscar chaves de cada provedor:

```javascript
async function getOpenAIKey() {
  const fromEnv = getRuntimeEnv('WORION_OPENAI_KEY');
  if (fromEnv) return fromEnv;
  const rows = await getVaultRows('openai');
  const key = findVaultValue(rows, ['api_key', 'key', 'openai_key', 'value']);
  if (!key) throw new Error('OpenAI key nao encontrada na Vault Supabase (provider=openai).');
  return key;
}

async function getDeepSeekKey() {
  const fromEnv = getRuntimeEnv('WORION_DEEPSEEK_KEY');
  if (fromEnv) return fromEnv;
  const byId = await getVaultValueById(43);
  if (byId) return byId;
  const rows = await getVaultRows('deepseek');
  const key = findVaultValue(rows, ['api_key', 'deepseek_api_key', 'key', 'value']);
  if (!key) throw new Error('DeepSeek key nao encontrada na Vault Supabase (provider=deepseek).');
  return key;
}

async function getAnthropicKey() {
  const fromEnv = getRuntimeEnv('WORION_ANTHROPIC_KEY');
  if (fromEnv) return fromEnv;
  const rows = await getVaultRows('claude.ai');
  const key = findVaultValue(rows, ['api_key', 'key', 'anthropic_key', 'value']);
  if (!key) throw new Error('Anthropic key nao encontrada na Vault Supabase (provider=claude.ai).');
  return key;
}
```

**Características:**
- ✅ Prioriza variáveis de ambiente (`WORION_*_KEY`)
- ✅ Fallback para Vault Supabase por provider
- ✅ DeepSeek também tenta buscar por ID (43) direto
- ✅ Erro claro quando key não encontrada

### 2.2. Função auxiliar para determinar provider

```javascript
function getModelProvider(modelId) {
  const normalized = String(modelId || '').toLowerCase();
  if (normalized.includes('deepseek')) return 'deepseek';
  if (normalized.includes('claude') || normalized.includes('anthropic')) return 'anthropic';
  if (normalized.includes('gpt') || normalized.includes('openai')) return 'openai';
  return 'deepseek';
}
```

**Características:**
- ✅ Detecta provider baseado no nome do modelo
- ✅ Fallback para `deepseek` se incerto
- ✅ Suporta variações de nomes (claude/anthropic, gpt/openai)

### 2.3. Normalização de mensagens para DeepSeek

DeepSeek não suporta `content` como array de objetos. Adicionada função de normalização:

```javascript
function normalizeMessagesForDeepSeek(messages = []) {
  return messages.map(message => {
    const normalized = { ...message };
    let content = message.content;
    if (Array.isArray(content)) {
      const textParts = content.map(part => {
        if (!part) return '';
        if (typeof part === 'string') return part;
        if (part.type === 'text') return part.text || part.content || '';
        if (part.type === 'image_url') return ''; // DeepSeek não suporta imagens
        return part.text || part.content || '';
      }).filter(Boolean);
      content = textParts.join('\n');
    }
    normalized.content = typeof content === 'string' ? content : String(content || '');
    delete normalized.attachments;
    delete normalized.createdAt;
    return normalized;
  });
}
```

**Características:**
- ✅ Converte arrays de content para string
- ✅ Ignora imagens (DeepSeek não suporta)
- ✅ Remove campos não esperados pela API

### 2.4. Funções para chamar cada provedor

#### callOpenAIProvider

```javascript
async function callOpenAIProvider(model, messages, options = {}) {
  const apiKey = await getOpenAIKey();
  const payload = {
    model,
    messages,
    temperature: options.temperature ?? 0.4,
    max_completion_tokens: options.max_tokens || options.max_completion_tokens || 4000
  };

  if (options.tools?.length) {
    payload.tools = options.tools;
    payload.tool_choice = options.tool_choice ?? 'auto';
  }

  const response = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${apiKey}`
    },
    body: JSON.stringify(payload)
  });

  const text = await response.text();
  if (!response.ok) {
    throw new Error(`OpenAI error ${response.status}: ${text.slice(0, 300)}`);
  }

  const data = JSON.parse(text || '{}');
  if (data.error) {
    throw new Error(`OpenAI error: ${JSON.stringify(data.error).slice(0, 300)}`);
  }

  return {
    content: data.choices?.[0]?.message?.content || '',
    model: data.model || model,
    usage: data.usage || {},
    finish_reason: data.choices?.[0]?.finish_reason || 'stop',
    tool_calls: data.choices?.[0]?.message?.tool_calls || []
  };
}
```

**Características:**
- ✅ Chama `https://api.openai.com/v1/chat/completions`
- ✅ Suporta `tools` e `tool_choice`
- ✅ Retorna formato normalizado
- ✅ Erro com slice limitado (300 chars)

